8	// TestRoutingPreferenceIdentity pins the iota ordering of RoutingPreference
9	// values so callers (and the projection helpers landing in later beads) can
10	// rely on the constants being stable rather than reshuffled by a future edit
11	// to the const block.
12	func TestRoutingPreferenceIdentity(t *testing.T) {
13		cases := []struct {
14			name string
15			got  RoutingPreference
16			want int
17		}{
18			{"unknown", RoutingPreferenceUnknown, 0},
19			{"available", RoutingPreferenceAvailable, 1},
20			{"blocked", RoutingPreferenceBlocked, 2},
21		}
22		for _, tc := range cases {
23			if int(tc.got) != tc.want {
24				t.Errorf("RoutingPreference %s = %d, want %d", tc.name, int(tc.got), tc.want)
25			}
26		}
27	
28		// Identity: two references to the same constant compare equal.
29		if RoutingPreferenceAvailable != RoutingPreferenceAvailable {
30			t.Error("RoutingPreferenceAvailable not equal to itself")
31		}
32		// Distinctness: every enumerated value is distinct.
33		all := []RoutingPreference{
34			RoutingPreferenceUnknown,
35			RoutingPreferenceAvailable,
36			RoutingPreferenceBlocked,
37		}
38		seen := map[RoutingPreference]struct{}{}
39		for _, v := range all {
40			if _, dup := seen[v]; dup {
41				t.Errorf("duplicate RoutingPreference value: %d", v)
42			}
43			seen[v] = struct{}{}
44		}
45	}
