57			{QuotaStale, "stale"},
58			{QuotaBlocked, "blocked"},
59			{QuotaUnavailable, "unavailable"},
60			{QuotaUnauthenticated, "unauthenticated"},
61			{QuotaUnknown, "unknown"},
62		}
63		for _, tc := range cases {
