79	// TestErrAliasNotResolvableIdentity ensures the sentinel is a non-nil,
80	// errors.Is-comparable singleton with a stable message. Callers (notably
81	// the conformance suite landing in BEAD-HARNESS-IF-02) rely on
82	// errors.Is(err, ErrAliasNotResolvable) to assert negative-path coverage
83	// of ResolveModelAlias.
84	func TestErrAliasNotResolvableIdentity(t *testing.T) {
85		if ErrAliasNotResolvable == nil {
86			t.Fatal("ErrAliasNotResolvable is nil")
87		}
88		if got, want := ErrAliasNotResolvable.Error(), "model alias not resolvable from snapshot"; got != want {
89			t.Errorf("ErrAliasNotResolvable.Error() = %q, want %q", got, want)
90		}
91		if !errors.Is(ErrAliasNotResolvable, ErrAliasNotResolvable) {
92			t.Error("errors.Is(ErrAliasNotResolvable, ErrAliasNotResolvable) = false")
93		}
94		wrapped := errWrap{inner: ErrAliasNotResolvable}
95		if !errors.Is(wrapped, ErrAliasNotResolvable) {
96			t.Error("errors.Is on wrapped sentinel = false")
97		}
98		other := errors.New("model alias not resolvable from snapshot")
99		if errors.Is(other, ErrAliasNotResolvable) {
100			t.Error("a freshly-allocated error with the same message must not match the sentinel")
101		}
102	}
